// ✅ 필수값 검사 (통합 업로드 구조: files[])
const body = $input.first().json.body || $input.first().json;

const required = ['prompt_p1', 'topic', 'keywords', 'category'];
const missing = required.filter(k => !body[k]);

if (missing.length > 0) {
  throw new Error(`필수값 누락: ${missing.join(', ')}`);
}

// files 검증 (최대 10개)
const files = body.files || [];
if (files.length > 10) {
  throw new Error(`files 최대 10개 (현재: ${files.length})`);
}
if (files.length === 0) {
  throw new Error('파일이 1개 이상 필요합니다.');
}

// clip_duration: 4 또는 8만 허용, 그 외는 8로 고정
const rawDur = parseInt(body.clip_duration) || 8;
const clipDuration = (rawDur <= 4) ? 4 : 8;

// 기본값 처리
const useMedia = body.use_media || 'forced';
const uploadTarget = body.upload_target || 'youtube';

// files 정규화
const finalFiles = files.map(f => ({
  type: f.type || 'image',
  url: f.url || '',
  vision_analysis: f.vision_analysis || '',
  video_analysis: f.video_analysis || '',
  use_directly: f.use_directly !== false
}));

// 하위 호환: clips[] → files[] 변환
let compatFiles = finalFiles;
if (finalFiles.length === 0 && body.clips && body.clips.length > 0) {
  compatFiles = body.clips.map(c => ({
    type: 'image',
    url: c.image_url || '',
    vision_analysis: c.vision_analysis || '',
    video_analysis: '',
    use_directly: true
  }));
}

// 언어 감지
const isKorean = /[\uAC00-\uD7A3]/.test(body.prompt_p1 + body.topic);
const translateMode = body.translate_mode || 'auto';
const needsTranslation = translateMode === 'on' || (translateMode === 'auto' && isKorean);

return [{
  json: {
    ...body,
    production_id: body.productionId || body.production_id || null,
    clips: JSON.stringify(compatFiles),
    clip_duration: clipDuration,
    use_media: useMedia,
    upload_target: uploadTarget,
    prompt_lang_detected: isKorean ? 'ko' : 'en',
    needs_translation: needsTranslation,
    validated_at: new Date().toISOString()
  }
}];

const job = $input.first().json;

return [{
  json: {
    success: true,
    job_id: job.id,
    production_id: job.production_id || null,
    status: job.status,
    message: 'Job이 큐에 등록되었습니다.',
    created_at: job.created_at
  }
}];

// ✅ 필수값 검사
const body = $input.first().json.body || $input.first().json;

const required = ['prompt_p1', 'topic', 'keywords', 'category', 'use_media', 'upload_target'];
const missing = required.filter(k => !body[k]);

if (missing.length > 0) {
  throw new Error(`필수값 누락: ${missing.join(', ')}`);
}

// use_media 값 검증
if (!['auto', 'forced', 'off'].includes(body.use_media)) {
  throw new Error(`use_media 값 오류: ${body.use_media} (auto/forced/off 중 하나여야 함)`);
}

// upload_target 검증
if (body.upload_target !== 'youtube') {
  throw new Error(`upload_target 오류: ${body.upload_target} (현재 youtube만 지원)`);
}

// 이미지 슬롯 매핑 (IMG_1 ~ IMG_4)
const images = body.images || [];
const imageSlots = {};
for (let i = 0; i < 4; i++) {
  imageSlots[`IMG_${i + 1}`] = images[i] || null;
}

// 언어 감지 (한글 포함 여부)
const isKorean = /[\uAC00-\uD7A3]/.test(body.prompt_p1 + body.topic);
const translateMode = body.translate_mode || 'auto';
const needsTranslation = translateMode === 'on' || (translateMode === 'auto' && isKorean);

return [{
  json: {
    ...body,
    image_slots: imageSlots,
    prompt_lang_detected: isKorean ? 'ko' : 'en',
    needs_translation: needsTranslation,
    validated_at: new Date().toISOString()
  }
}];

const job = $input.first().json;

return [{
  json: {
    success: true,
    job_id: job.id,
    production_id: job.production_id || null,
    status: job.status,
    message: 'Job이 큐에 등록되었습니다.',
    created_at: job.created_at
  }
}];
